import React, { useEffect, useState } from 'react';
import { getLeads } from '../../api/leadApi';
import { getVehicles } from '../../api/vehicleApi';
import { getStaff } from '../../api/adminUserApi';
import { getSales } from '../../api/saleApi';
import { getAppointments } from '../../api/appointmentApi';
import '../../styles/dashboard.css';
import '../../styles/main.css';

export default function AdminDashboard() {
  const [stats, setStats] = useState({
    totalLeads: 0,
    activeUsers: 0,
    availableVehicles: 0,
    pendingAppointments: 0,
    monthlyRevenue: 0,
    lostLeads: 0,
    convertedLeads: 0,
    salesData: [],
    vehicleStats: { available: 0, sold: 0 },
    recentActivity: [],
  });

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      setError(null);

      const [leadsRes, vehiclesRes, staffRes, salesRes, appointmentsRes] = await Promise.all([
        getLeads().catch(e => {
          console.error("Leads API error:", e.response?.status, e.response?.data);
          return { data: [] };
        }),
        getVehicles().catch(e => {
          console.error("Vehicles API error:", e.response?.status, e.response?.data);
          return { data: [] };
        }),
        getStaff().catch(e => {
          console.error("Staff API error:", e.response?.status, e.response?.data);
          return { data: [] };
        }),
        getSales().catch(e => {
          console.error("Sales API error:", e.response?.status, e.response?.data);
          return { data: [] };
        }),
        getAppointments().catch(e => {
          console.error("Appointments API error:", e.response?.status, e.response?.data);
          return { data: [] };
        }),
      ]);

      const leads = leadsRes.data || [];
      const vehicles = vehiclesRes.data || [];
      const staff = staffRes.data || [];
      const sales = salesRes.data || [];
      const appointments = appointmentsRes.data || [];

      // Calculate stats
      const availableVehicles = vehicles.filter(v => v.status === 'available').length;
      const soldVehicles = vehicles.filter(v => v.status === 'sold').length;
      const pendingAppointments = appointments.filter(a => a.status === 'pending' || a.status === 'scheduled').length;
      const convertedLeads = leads.filter(l => l.status === 'converted').length;
      const lostLeads = leads.filter(l => l.status === 'lost').length;

      // Calculate monthly revenue (sum of sales amounts)
      const monthlyRevenue = sales.reduce((sum, sale) => sum + (sale.amount || 0), 0);

      // Prepare sales data for the last 6 months
      const salesData = sales.slice(-6).map(sale => ({
        month: new Date(sale.createdAt).toLocaleDateString('en-US', { month: 'short' }),
        revenue: sale.amount || 0,
      }));

      // Prepare recent activity (latest 5 items)
      const recentActivity = [
        ...sales.slice(-2).map(s => ({
          type: 'sale',
          title: `Sale Completed`,
          description: `${s.vehicleId} sold`,
          time: new Date(s.createdAt).toLocaleDateString(),
          status: 'completed'
        })),
        ...leads.slice(-2).map(l => ({
          type: 'lead',
          title: `New Lead`,
          description: `Inquiry for ${l.interestedVehicle || 'a vehicle'}`,
          time: new Date(l.createdAt).toLocaleDateString(),
          status: 'new'
        }))
      ].slice(0, 5);

      setStats({
        totalLeads: leads.length,
        activeUsers: staff.filter(s => !s.isDeleted).length,
        availableVehicles,
        pendingAppointments,
        monthlyRevenue,
        lostLeads,
        convertedLeads,
        salesData,
        vehicleStats: { available: availableVehicles, sold: soldVehicles },
        recentActivity,
      });

    } catch (err) {
      console.error('Error fetching dashboard data:', err);
      setError(err.message || 'Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="appShell">
        <Sidebar isOpen={sidebarOpen} onClose={() => setSidebarOpen(false)} />
        <div className="appMain">
          <div className="appContent">
            <p style={{ padding: '40px', textAlign: 'center' }}>Loading dashboard...</p>
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="appShell">
        <Sidebar isOpen={sidebarOpen} onClose={() => setSidebarOpen(false)} />
        <div className="appMain">
          <div className="appContent" style={{ padding: '40px' }}>
            <p style={{ color: '#ef4444', marginBottom: '16px' }}>{error}</p>
            <button className="btn btnPrimary" onClick={fetchDashboardData}>Retry</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="appShell">
      <Sidebar isOpen={sidebarOpen} onClose={() => setSidebarOpen(false)} />
      <div className="appMain">
        <div className="appContent">
          <div className="dashboard-container">
      <div className="dashboard-header">
        <h1>Admin Dashboard</h1>
        <p className="dashboard-subtitle">Welcome back! Here's your daily overview</p>
      </div>

      {/* First Row - KPI Cards */}
      <div className="dashboard-grid">
        {/* Total Leads Card */}
        <div className="dashboard-card">
          <div className="card-header">
            <h3>Total Leads</h3>
            <div className="card-icon leads-icon">👥</div>
          </div>
          <div className="card-value">{stats.totalLeads.toLocaleString()}</div>
          <div className="card-footer positive">+12.5% from last month</div>
        </div>

        {/* Active Users Card */}
        <div className="dashboard-card">
          <div className="card-header">
            <h3>Active Users</h3>
            <div className="card-icon users-icon">👤</div>
          </div>
          <div className="card-value">{stats.activeUsers}</div>
          <div className="card-footer positive">+8.2% from last month</div>
        </div>

        {/* Available Vehicles Card */}
        <div className="dashboard-card">
          <div className="card-header">
            <h3>Available Vehicles</h3>
            <div className="card-icon vehicles-icon">🚗</div>
          </div>
          <div className="card-value">{stats.availableVehicles}</div>
          <div className="card-footer negative">-5 from last week</div>
        </div>
      </div>

      {/* Second Row - More KPI Cards */}
      <div className="dashboard-grid">
        {/* Monthly Revenue Card */}
        <div className="dashboard-card">
          <div className="card-header">
            <h3>Monthly Revenue</h3>
            <div className="card-icon revenue-icon">💲</div>
          </div>
          <div className="card-value">${(stats.monthlyRevenue / 1000).toFixed(0)}K</div>
          <div className="card-footer positive">+15.3% from last month</div>
        </div>

        {/* Pending Appointments Card */}
        <div className="dashboard-card">
          <div className="card-header">
            <h3>Pending Appointments</h3>
            <div className="card-icon appointments-icon">📅</div>
          </div>
          <div className="card-value">{stats.pendingAppointments}</div>
          <div className="card-footer positive">+3 new today</div>
        </div>

        {/* Market Risk Card */}
        <div className="dashboard-card">
          <div className="card-header">
            <h3>Market Risk Level</h3>
            <div className="card-icon market-risk-icon">⚠️</div>
          </div>
          <div className="card-value" style={{ color: '#10b981', fontSize: '28px' }}>Low</div>
          <div className="card-footer neutral">Stable conditions</div>
        </div>
      </div>

      {/* Charts & Activity Section */}
      <div className="dashboard-2col">
        {/* Sales Performance Chart */}
        <div className="chart-container">
          <h3 className="chart-title">Sales Performance</h3>
          <p className="chart-subtitle">Monthly revenue trend</p>
          <div style={{ height: '250px', display: 'flex', alignItems: 'flex-end', gap: '12px', justifyContent: 'center' }}>
            {stats.salesData.length > 0 ? (
              stats.salesData.map((data, idx) => {
                const maxRevenue = Math.max(...stats.salesData.map(d => d.revenue));
                const height = maxRevenue > 0 ? (data.revenue / maxRevenue) * 100 : 0;
                return (
                  <div key={idx} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', flex: 1 }}>
                    <div 
                      style={{ 
                        width: '100%', 
                        height: `${height}%`, 
                        background: 'linear-gradient(180deg, #4CAF50, #45a049)',
                        borderRadius: '6px 6px 0 0',
                        minHeight: '20px',
                        marginBottom: '8px'
                      }}
                    ></div>
                    <span style={{ fontSize: '12px', color: '#6b7280' }}>{data.month}</span>
                  </div>
                );
              })
            ) : (
              <p style={{ color: '#6b7280' }}>No sales data available</p>
            )}
          </div>
        </div>

        {/* Vehicle Inventory Chart */}
        <div className="chart-container">
          <h3 className="chart-title">Vehicle Inventory Status</h3>
          <p className="chart-subtitle">Available vs sold vehicles</p>
          <div style={{ height: '250px', display: 'flex', alignItems: 'flex-end', gap: '40px', justifyContent: 'center', padding: '20px 0' }}>
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '12px' }}>
              <div 
                style={{ 
                  width: '60px',
                  height: `${(stats.vehicleStats.available / (stats.vehicleStats.available + stats.vehicleStats.sold) * 180) || 80}px`,
                  background: 'linear-gradient(180deg, #dcfce7, #22c55e)',
                  borderRadius: '6px'
                }}
              ></div>
              <span style={{ fontSize: '12px', fontWeight: '600', color: '#1f2937' }}>Available</span>
              <span style={{ fontSize: '18px', fontWeight: '700', color: '#22c55e' }}>{stats.vehicleStats.available}</span>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '12px' }}>
              <div 
                style={{ 
                  width: '60px',
                  height: `${(stats.vehicleStats.sold / (stats.vehicleStats.available + stats.vehicleStats.sold) * 180) || 80}px`,
                  background: 'linear-gradient(180deg, #1a2332, #0f1419)',
                  borderRadius: '6px'
                }}
              ></div>
              <span style={{ fontSize: '12px', fontWeight: '600', color: '#1f2937' }}>Sold</span>
              <span style={{ fontSize: '18px', fontWeight: '700', color: '#1a2332' }}>{stats.vehicleStats.sold}</span>
            </div>
          </div>
        </div>
      </div>

      {/* Activity & Quick Actions Section */}
      <div className="dashboard-2col">
        {/* Recent System Activity */}
        <div className="activity-container">
          <div className="activity-header">
            <div>
              <h3>Recent System Activity</h3>
              <p className="activity-subtitle">Latest transactions and system updates</p>
            </div>
            <a href="#" className="activity-view-all">View All</a>
          </div>
          <ul className="activity-list">
            {stats.recentActivity.length > 0 ? (
              stats.recentActivity.map((activity, idx) => (
                <li key={idx} className="activity-item">
                  <div className={`activity-icon ${activity.type}`}>
                    {activity.type === 'sale' && '💰'}
                    {activity.type === 'lead' && '👥'}
                    {activity.type === 'appointment' && '📅'}
                    {activity.type === 'user' && '👤'}
                  </div>
                  <div className="activity-content">
                    <p className="activity-title">{activity.title}</p>
                    <p className="activity-description">{activity.description}</p>
                    <p className="activity-time">📅 {activity.time}</p>
                  </div>
                  <span className={`activity-badge ${activity.status}`}>{activity.status}</span>
                </li>
              ))
            ) : (
              <li style={{ padding: '20px', textAlign: 'center', color: '#6b7280' }}>No recent activity</li>
            )}
          </ul>
        </div>

        {/* Quick Actions */}
        <div className="quick-actions">
          <h3>Quick Actions</h3>
          <div className="actions-grid">
            <button className="action-button primary">
              <span style={{ fontSize: '18px' }}>➕</span>
              Add New Vehicle
            </button>
            <button className="action-button primary">
              <span style={{ fontSize: '18px' }}>👤</span>
              Create User
            </button>
            <button className="action-button secondary">
              <span style={{ fontSize: '18px' }}>📊</span>
              Generate Report
            </button>
            <button className="action-button success">
              <span style={{ fontSize: '18px' }}>📈</span>
              View Market Analysis
            </button>
          </div>
        </div>
      </div>
          </div>
        </div>
      </div>
    </div>
  );
}
